INSERT INTO `dealer_info` (`id`, `user_id`, `city_id`, `city_code_id`, `company`, `nif_number`, `address`, `website`, `firma`, `email`, `logotype`, `description`, `is_new_auto`, `is_old_auto`, `rating`) VALUES
(1, 6, 2, 134, 'Engines and tools', '12345674567', 'Avenida de Lourdes, 18', NULL, 'Engines and tools', 'email@mail.com', '89392.png', 'Сайт рыбатекст поможет дизайнеру, верстальщику, вебмастеру сгенерировать несколько абзацев более менее осмысленного текста рыбы на русском языке, а начинающему оратору отточить навык публичных выступлений в домашних условиях. При создании генератора мы использовали небезизвестный универсальный код речей. Текст генерируется абзацами случайным образом от двух до десяти предложений в абзаце, что позволяет сделать текст более привлекательным и живым для визуально-слухового восприятия.', 1, 0, 0);
