INSERT INTO `pack` (`id`, `name`, `description`, `price`, `label`, `bg_class`) VALUES
(2, '<span class="tabMulNumber">x20</span><span class="tabTitle">Увеличение<br/>звонков</span>', '<div class="addAdvertServiceDescriptionTitle">VENTA R&Aacute;PIDA</div>\r\n<div class="addAdvertServiceDescriptionText">Ваше предложение увидит максимум посетителей &mdash; это увеличит шансы на быструю и выгодную продажу. Объявление будет выделено цветом, поднято в топ, размещено в специальном блоке на главной странице, на странице марки и в выдаче объявлений.</div>', 6.99, 'x20', 'servicePremium service20'),
(3, '<span class="tabMulNumber">x10</span><span class="tabTitle">Увеличение<br/>звонков</span>', '<div class="addAdvertServiceDescriptionTitle">VENTA EXPRESS</div>\r\n<div class="addAdvertServiceDescriptionText">Ваше предложение увидит максимум посетителей &mdash; это увеличит шансы на быструю и выгодную продажу. Объявление будет выделено цветом, поднято в топ, размещено в специальном блоке на главной странице, на странице марки и в выдаче объявлений.</div>', 4.99, 'x10', 'servicePremium service10');
