INSERT INTO `product_info` (`id`, `product_id`, `generation_id`, `board_id`, `gas_type_id`, `gas_transmission_id`, `gear_type_id`, `modification_id`, `color_id`, `shape_id`, `price`, `year`, `probeg`, `wheel`, `is_gas_baloon`, `owners`, `vin`, `description`, `nds`, `torg`, `garant`) VALUES
(3, 3, 1, 67, 58, 60, 63, 1, 74, 2, 10000, '1999', '15000', 1, 1, 0, '12345634567936723', 'Составляя текст объявления, помните, что самый правильный подход к его подготовке – честность и детальность описания автомобиля. Многие сайты предлагают стандартные формы заполнения, какие-то более подробные, какие-то – менее. На am.ru, например, очень подробная форма, которая позволяет составить полное описание машины. Но оно стандартно для всех, а вот поле для комментариев заполняется индивидуально, носит более эмоциональную окраску и создаёт образ автомобиля и его владельца.', NULL, NULL, NULL),
(5, 5, NULL, NULL, 93, 103, 109, 6, 72, 2, 1234567, '2000', '1222', NULL, NULL, NULL, NULL, 'О чем стоит написать:\r\n    - регулярно ли делалось тех.обслуживание,\r\n    - какие ремонтные работы производились,\r\n    - какие расходные материалы менялись и как давно', NULL, NULL, NULL),
(6, 6, NULL, NULL, 95, 105, 107, 7, 76, 4, 1300, '1999', '122212', NULL, NULL, NULL, NULL, 'О чем стоит написать:\r\n    - регулярно ли делалось тех.обслуживание,\r\n    - какие ремонтные работы производились,\r\n    - какие расходные материалы менялись и как давно\r\n', NULL, NULL, NULL),
(7, 7, NULL, NULL, 94, 105, 114, 8, NULL, 2, 1333, '1990', '12000', NULL, NULL, NULL, NULL, '', NULL, NULL, NULL),
(8, 8, 1, 67, 58, 60, 63, 1, NULL, 2, 12000, '1998', '1200', 0, 0, NULL, '123456782671123483', 'Более подробную информацию об официальном расходе топлива и официальных удельных выбросах CO2 новых легковых автомобилей можно получить из "Руководства по расходу топлива, выбросам CO2 и расходу электроэнергии новых легковых автомобилей". Руководство можно получить бесплатно во всех дилерских центрах, а также на веб-сайте Deutsche Automobil Treuhand GmbH: www.dat.de.', 0, 1, 1);
