INSERT INTO `question` (`id`, `name`, `sortorder`) VALUES
(1, 'Регистрация и продление домена', NULL);
INSERT INTO `question_answer` (`id`, `question_id`, `name`, `content`, `sortorder`, `is_show`) VALUES
(1, 1, 'Что такое домен и для чего он нужен?', '1. Авторизуйтесь в Личном кабинете на сайте.<br /><br />2. Найдите доменное имя, которое нужно продлить. <br />Наведите курсор на дату окончания регистрации домена. Нажмите Продлить. Или нажмите на 3 точки справа и в выпадающем списке нажмите Продлить<br /><br />3. Выберите период продления домена. Домены в зонах .RU, .РФ и .SU можно продлить на 1 год, международные домены на срок от 1 года до 10 лет. <br /><br />4. Включите или отключите функцию &laquo;Автопродление&raquo;. Затем проверьте стоимость продления и нажмите Оформить заказ', 1, 1),
(2, 1, 'Почему у вас такие дешевые цены на регистрацию доменов?', '1. Авторизуйтесь в Личном кабинете на сайте.<br /><br />2. Найдите доменное имя, которое нужно продлить. <br />Наведите курсор на дату окончания регистрации домена. Нажмите Продлить. Или нажмите на 3 точки справа и в выпадающем списке нажмите Продлить<br /><br />3. Выберите период продления домена. Домены в зонах .RU, .РФ и .SU можно продлить на 1 год, международные домены на срок от 1 года до 10 лет. <br /><br />4. Включите или отключите функцию &laquo;Автопродление&raquo;. Затем проверьте стоимость продления и нажмите Оформить заказ', 2, 1),
(3, 1, 'Я зарегистрировал домен, что дальше?', '1. Авторизуйтесь в Личном кабинете на сайте.<br /><br />2. Найдите доменное имя, которое нужно продлить. <br />Наведите курсор на дату окончания регистрации домена. Нажмите Продлить. Или нажмите на 3 точки справа и в выпадающем списке нажмите Продлить<br /><br />3. Выберите период продления домена. Домены в зонах .RU, .РФ и .SU можно продлить на 1 год, международные домены на срок от 1 года до 10 лет. <br /><br />4. Включите или отключите функцию &laquo;Автопродление&raquo;. Затем проверьте стоимость продления и нажмите Оформить заказ', 3, 1);
