INSERT INTO `service` (`id`, `title`, `description`, `price`, `days`, `icon`, `icon_gray`, `type`, `parameter`, `is_button`) VALUES
(1, 'Премиум-размещение', 'Ваше объявление будет показываться на самом заметном месте сайта &mdash; на главной странице, в категориях над обычными объявлениями и на страницах результатов поиска.<br /> Стоимость услуги &mdash; 5 евро в сутки.', 50, 7, '<svg width="29" height="30" viewBox="0 0 29 30" fill="none" xmlns="http://www.w3.org/2000/svg">\r\n<path d="M28 14.7637C28 22.2195 21.9558 28.2637 14.5 28.2637M28 14.7637C28 7.30783 21.9558 1.26367 14.5 1.26367M28 14.7637H22.6M14.5 28.2637C7.04416 28.2637 1 22.2195 1 14.7637M14.5 28.2637V22.8637M1 14.7637C1 7.30783 7.04416 1.26367 14.5 1.26367M1 14.7637H6.4M14.5 1.26367V6.66367" stroke="#616161" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/>\r\n<path d="M14.5 28.2637C21.9558 28.2637 28 22.2195 28 14.7637C28 7.30783 21.9558 1.26367 14.5 1.26367C7.04416 1.26367 1 7.30783 1 14.7637C1 22.2195 7.04416 28.2637 14.5 28.2637Z" fill="#F5AA01"/>\r\n<path d="M28 14.7637C28 22.2195 21.9558 28.2637 14.5 28.2637M28 14.7637C28 7.30783 21.9558 1.26367 14.5 1.26367M28 14.7637H22.6M14.5 28.2637C7.04416 28.2637 1 22.2195 1 14.7637M14.5 28.2637V22.8637M1 14.7637C1 7.30783 7.04416 1.26367 14.5 1.26367M1 14.7637H6.4M14.5 1.26367V6.66367" stroke="#616161" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/>\r\n</svg>', '<svg width="24" height="24" viewBox="0 0 29 29" fill="none" xmlns="http://www.w3.org/2000/svg">\r\n                                                                                <path d="M28 14.5C28 21.9558 21.9558 28 14.5 28M28 14.5C28 7.04416 21.9558 1 14.5 1M28 14.5H22.6M14.5 28C7.04416 28 1 21.9558 1 14.5M14.5 28V22.6M1 14.5C1 7.04416 7.04416 1 14.5 1M1 14.5H6.4M14.5 1V6.4" stroke="#616161" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/>\r\n                                                                        </svg>', 0, 'days', 0),
(2, 'Выделить', 'Ваше объявление будет показываться на странице результатов поиска и в своей категории, оно отмечатся особой иконкой и отображаются другой цветовой гаммой. BONUS При этом оно поднимется на первое место в результатах поиска бесплатно. Цена - 3 евро/сутки.', 30, 7, '<svg width="32" height="25" viewBox="0 0 32 25" fill="none" xmlns="http://www.w3.org/2000/svg">\r\n<path d="M1 12.5273C1 12.5273 6.39303 1.74121 15.8308 1.74121C25.2687 1.74121 30.6617 12.5273 30.6617 12.5273C30.6617 12.5273 25.2687 23.3134 15.8308 23.3134C6.39303 23.3134 1 12.5273 1 12.5273Z" fill="#F5AA01"/>\r\n<path d="M15.8308 16.5721C18.0647 16.5721 19.8756 14.7611 19.8756 12.5273C19.8756 10.2934 18.0647 8.4825 15.8308 8.4825C13.597 8.4825 11.7861 10.2934 11.7861 12.5273C11.7861 14.7611 13.597 16.5721 15.8308 16.5721Z" fill="#F5AA01"/>\r\n<path d="M1 12.5273C1 12.5273 6.39303 1.74121 15.8308 1.74121C25.2687 1.74121 30.6617 12.5273 30.6617 12.5273C30.6617 12.5273 25.2687 23.3134 15.8308 23.3134C6.39303 23.3134 1 12.5273 1 12.5273Z" stroke="#616161" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/>\r\n<path d="M15.8308 16.5721C18.0647 16.5721 19.8756 14.7611 19.8756 12.5273C19.8756 10.2934 18.0647 8.4825 15.8308 8.4825C13.597 8.4825 11.7861 10.2934 11.7861 12.5273C11.7861 14.7611 13.597 16.5721 15.8308 16.5721Z" stroke="#616161" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/>\r\n</svg>', '<svg width="32" height="25" viewBox="0 0 32 25" fill="none" xmlns="http://www.w3.org/2000/svg">\r\n<path d="M1 12.7861C1 12.7861 6.39303 2 15.8308 2C25.2687 2 30.6617 12.7861 30.6617 12.7861C30.6617 12.7861 25.2687 23.5721 15.8308 23.5721C6.39303 23.5721 1 12.7861 1 12.7861Z" stroke="#616161" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/>\r\n<path d="M15.8308 16.8308C18.0647 16.8308 19.8756 15.0199 19.8756 12.7861C19.8756 10.5522 18.0647 8.74129 15.8308 8.74129C13.597 8.74129 11.7861 10.5522 11.7861 12.7861C11.7861 15.0199 13.597 16.8308 15.8308 16.8308Z" stroke="#616161" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/>\r\n</svg>', 0, 'days', 0),
(3, 'Поднять', 'Ваше объявление поднимется на первое место в результатах поиска, как если бы оно было только что подано на сайт. BONUS На следующий день, в это же время, оно будет поднято ещё раз бесплатно. <br /> Стоимость услуги&nbsp;20 грн/сутки.', 20, 3, '<svg width="29" height="29" viewBox="0 0 29 29" fill="none" xmlns="http://www.w3.org/2000/svg">\r\n<path d="M14.5 28C21.9558 28 28 21.9558 28 14.5C28 7.04416 21.9558 1 14.5 1C7.04416 1 1 7.04416 1 14.5C1 21.9558 7.04416 28 14.5 28Z" fill="#F5AA01"/>\r\n<path d="M19.9 14.5L14.5 9.1L9.1 14.5" fill="#F5AA01"/>\r\n<path d="M19.9 14.5L14.5 9.1M14.5 9.1L9.1 14.5M14.5 9.1V19.9M28 14.5C28 21.9558 21.9558 28 14.5 28C7.04416 28 1 21.9558 1 14.5C1 7.04416 7.04416 1 14.5 1C21.9558 1 28 7.04416 28 14.5Z" stroke="#616161" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/>\r\n</svg>', '<svg width="29" height="29" viewBox="0 0 29 29" fill="none" xmlns="http://www.w3.org/2000/svg">\r\n<path d="M19.9 14.5L14.5 9.1M14.5 9.1L9.1 14.5M14.5 9.1V19.9M28 14.5C28 21.9558 21.9558 28 14.5 28C7.04416 28 1 21.9558 1 14.5C1 7.04416 7.04416 1 14.5 1C21.9558 1 28 7.04416 28 14.5Z" stroke="#616161" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/>\r\n</svg>', 0, 'count', 1),
(4, 'Спецпредложение', NULL, 2.99, 10, '<svg width="32" height="33" viewBox="0 0 32 33" fill="none" xmlns="http://www.w3.org/2000/svg">\r\n<path d="M16 23.2757C19.7656 23.2757 22.8182 20.2231 22.8182 16.4575C22.8182 12.6919 19.7656 9.63934 16 9.63934C12.2344 9.63934 9.18182 12.6919 9.18182 16.4575C9.18182 20.2231 12.2344 23.2757 16 23.2757Z" fill="#F5AA01"/>\r\n<path d="M16 1.45752V4.18479M16 28.7302V31.4575M5.39091 5.84843L7.32727 7.78479M24.6727 25.1302L26.6091 27.0666M1 16.4575H3.72727M28.2727 16.4575H31M5.39091 27.0666L7.32727 25.1302M24.6727 7.78479L26.6091 5.84843M22.8182 16.4575C22.8182 20.2231 19.7656 23.2757 16 23.2757C12.2344 23.2757 9.18182 20.2231 9.18182 16.4575C9.18182 12.6919 12.2344 9.63934 16 9.63934C19.7656 9.63934 22.8182 12.6919 22.8182 16.4575Z" stroke="#616161" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/>\r\n</svg>', '<svg width="32" height="33" viewBox="0 0 32 33" fill="none" xmlns="http://www.w3.org/2000/svg">\r\n<path d="M16 1.00195V3.72923M16 28.2747V31.002M5.39091 5.39286L7.32727 7.32923M24.6727 24.6747L26.6091 26.611M1 16.002H3.72727M28.2727 16.002H31M5.39091 26.611L7.32727 24.6747M24.6727 7.32923L26.6091 5.39286M22.8182 16.002C22.8182 19.7675 19.7656 22.8201 16 22.8201C12.2344 22.8201 9.18182 19.7675 9.18182 16.002C9.18182 12.2364 12.2344 9.18377 16 9.18377C19.7656 9.18377 22.8182 12.2364 22.8182 16.002Z" stroke="#616161" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/>\r\n</svg>', 0, 'days', 0);
